import React, { useState } from 'react';
import './CaseManagement.css';

const CaseManagement = ({ language }) => {
  const [filter, setFilter] = useState('all');

  const content = {
    en: {
      title: 'Case Management',
      filterAll: 'All',
      filterHarassment: 'Harassment',
      filterRagging: 'Ragging',
      filterCyber: 'Cyberbullying',
      caseId: 'Case ID',
      type: 'Type',
      severity: 'Severity',
      status: 'Status',
      date: 'Date'
    },
    hi: {
      title: 'मामला प्रबंधन',
      filterAll: 'सभी',
      filterHarassment: 'उत्पीड़न',
      filterRagging: 'रैगिंग',
      filterCyber: 'साइबरबुलिंग',
      caseId: 'मामला आईडी',
      type: 'प्रकार',
      severity: 'गंभीरता',
      status: 'स्थिति',
      date: 'तारीख'
    }
  };

  const text = content[language] || content.en;

  // Mock cases
  const cases = [
    { id: 'SAH-CASE-001', type: 'Harassment', severity: 'high', status: 'Under Review', date: '2026-03-01' },
    { id: 'SAH-CASE-002', type: 'Ragging', severity: 'medium', status: 'Resolved', date: '2026-02-28' },
    { id: 'SAH-CASE-003', type: 'Cyberbullying', severity: 'low', status: 'Under Review', date: '2026-02-27' }
  ];

  return (
    <div className="case-management">
      <div className="case-container">
        <h1>{text.title}</h1>

        <div className="filter-buttons">
          <button className={filter === 'all' ? 'active' : ''} onClick={() => setFilter('all')}>
            {text.filterAll}
          </button>
          <button className={filter === 'harassment' ? 'active' : ''} onClick={() => setFilter('harassment')}>
            {text.filterHarassment}
          </button>
          <button className={filter === 'ragging' ? 'active' : ''} onClick={() => setFilter('ragging')}>
            {text.filterRagging}
          </button>
          <button className={filter === 'cyber' ? 'active' : ''} onClick={() => setFilter('cyber')}>
            {text.filterCyber}
          </button>
        </div>

        <div className="case-table">
          <div className="table-header">
            <div>{text.caseId}</div>
            <div>{text.type}</div>
            <div>{text.severity}</div>
            <div>{text.status}</div>
            <div>{text.date}</div>
          </div>
          {cases.map((c) => (
            <div key={c.id} className="table-row">
              <div>{c.id}</div>
              <div>{c.type}</div>
              <div><span className={`severity-badge ${c.severity}`}>{c.severity}</span></div>
              <div>{c.status}</div>
              <div>{c.date}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default CaseManagement;
